#include<iostream>
using namespace std;

int main(){
    int n,m;
    cin >> n >> m;
    int _min = 1e9+10;
    for(int i=0;i<n;i++){
        int tmp;
        cin >> tmp;
        if(_min > tmp) _min = tmp;
    }
    for(int i=0;i<m;i++){
        int op,l,r;
        cin >> op >> l >> r;
        if(l <= _min && _min <= r){
            _min += op;
        }
        cout << _min << endl;
    }
}
